var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"응? 이 시커먼 건 뭐야? 이런 게 반입 품목에 있었던가?","JPN":"ん？　この真っ黒なやつはなんだろう？　こんなの搬入リストにあったっけ？","ENG":"Hmm? What's this black thing? Was this also included in the list?","TWN":"嗯？這個黑黑的東西是什麼？搬運清單上有這個嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"무슨 소리야. 품목 확인은 네 담당이잖아.","JPN":"何言ってんだよ。リスト確認はお前の仕事だろ？","ENG":"What are you talking about? You were the one in charge of confirming the list.","TWN":"你問我幹嘛？清單是你要負責確認的欸！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"알아. 목록에서 본 기억이 없으니까 그렇지.","JPN":"そうなんだけど。リストで見た覚えがなくてさ。","ENG":"I know. I'm asking you because I don't remember anything like this on the list.","TWN":"我知道，我不記得它有出現在清單上，所以才問你的嘛。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"그냥 어디다 따로 빼놔. 괜히 목록에 없는 거 들여보냈다가 큰일날 수도 있어.","JPN":"どっかに出しておけよ。リストにないもの入れて、大変なことになるかもしれないからさ。","ENG":"Just leave it out for now. We might get in trouble for bringing in something that hasn't been on the list.","TWN":"先放到其他地方吧，要是把清單上沒有的東西搬進去，到時候又要倒大楣。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"고작 그런 걸로 큰일… 나겠네. 요즘 헤론 님 가차없으시니까.","JPN":"それくらいで大変なことになるわけ……あるか。最近のヘロン様は容赦ないからな。","ENG":"Get in trouble for this? Yeah... you're right. Madam Heron's ruthless these days…","TWN":"不過就是搬個東西…確實很可能會倒大楣，海倫夫人最近喜怒無常。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"헤이븐 형님 닮아가는 거겠지. 간부 중에 제일 오래 같이 일하셨잖아.","JPN":"ヘイブン兄貴に似てきてるんだろ。幹部の中でも一番長いんだし。","ENG":"Maybe she's becoming more and more like Mr. Haven. She has been by his side longer than anyone else.","TWN":"應該就是越來越像天堂大哥吧，畢竟她是跟在大哥身邊的幹部中，資歷最久的一個。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"이건 일단 저쪽 컨테이너에 두고, 급한 것들부터 옮기자고.","JPN":"とりあえずこれはあっちのコンテナにおいて、急ぎのものから運ぼうぜ。","ENG":"Just leave that over by that container over there, and let's move these first.","TWN":"這就先放那邊的貨櫃裡，先搬那些比較急的吧！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"와! 새로운 장소!","JPN":"わーい！　初めての場所！","ENG":"Wow! A new place!","TWN":"哇！新的地方欸！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"놀 게……","JPN":"遊ぶもの……","ENG":"There's...","TWN":"好多……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":" 잔뜩이야!!","JPN":" いーっぱい！！","ENG":" so much to play with!!","TWN":"好玩的！！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"잔뜩…….","JPN":"いっぱい……","ENG":"So much...","TWN":"好……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"심심해…….","JPN":"暇……","ENG":"I'm bored already...","TWN":"無聊……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 할아버지한테 같이 오자고 할 걸.","JPN":"こんなことならおじいちゃんに一緒に行こうって頼めばよかったかな。","ENG":"Should've asked Grandpa to come along if I knew it was going to be like this...","TWN":"早知道就找爺爺一起來。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"……아니야, 오늘은 새 친구를 만나는 날이니까!","JPN":"……ううん、今日は新しい友達と会う日なんだから！","ENG":"No... Today's all about making new friends!","TWN":"……不行，今天是認識新朋友的日子！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"맞아. 친구들에게 멋진 모습을 보여 주려고 호출기도 안 가져왔잖아.  ","JPN":"そうだよ。友達にカッコいい姿を見せようと思って呼び出し機も持ってこなかったもん。  ","ENG":"Right! I didn't even bring my beeper just so I can look cool in front of them!  ","TWN":"沒錯，為了在新朋友面前酷一點，我還特地沒帶呼叫器出來呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"<color=#ffd34c>초퍼</color>는 언제 올까? 빨리 만나면 좋겠다.","JPN":"<color=#ffd34c>チョッパー</color>はいつ来るのかな？　早く会いたいなぁ。","ENG":"I wonder when <color=#ffd34c>Chopper</color> will show up? I'm so excited!","TWN":"不過<color=#ffd34c>喬巴</color>怎麼還沒來？好想趕快見到她喔。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};